                // Calculate the local position offset for the current soldier
                Vector3 soldierOffset = new Vector3(
                    (x - sideLength / 2) * offsetBetweenSoldiers,  // Side offset
                    commander.transform.position.y,                // Maintain the same y position as the commander
                    (z - sideLength / 2) * offsetBetweenSoldiers   // Depth offset
                ) - (Vector3.forward * offsetFormationBehindCommander); // Move behind the commander

                // Apply the local offset to the world position where we want the commander
