```csharp
using UnityEngine;
using UnityEngine.AI;

public class RTSController : MonoBehaviour
{
    public LayerMask commanderLayerMask; // Layer mask to filter out commanders when raycasting
    public LayerMask groundLayerMask; // Layer mask to filter out the ground when setting target position

    private GameObject currentCommander = null; // Currently selected commander

    void Update()
    {
        if (Input.GetMouseButtonDown(0)) // Left mouse button clicked
        {
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            RaycastHit hit;

            if (Physics.Raycast(ray, out hit, Mathf.Infinity, commanderLayerMask))
            {
                // The ray hit a commander, so set it as the current unit
                currentCommander = hit.collider.gameObject;
            }
            else if (Physics.Raycast(ray, out hit, Mathf.Infinity, groundLayerMask) && currentCommander != null)
            {
                // The ray hit the ground, so if we have a current commander, set the target position
                NavMeshAgent commanderAgent = currentCommander.GetComponent<NavMeshAgent>();
                if (commanderAgent != null)
                {
                    commanderAgent.SetDestination(hit.point);
                }
            }
        }

        if (Input.GetMouseButtonDown(1)) // Right mouse button clicked
        {
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            RaycastHit hit;

            if (!Physics.Raycast(ray, out hit, Mathf.Infinity, commanderLayerMask))
            {
                // The ray did not hit a commander, so clear the current unit
                currentCommander = null;
            }
        }
    }
}
```

Here's what the script does:

- The `commanderLayerMask` is used to filter clicks that only hit objects on the commander layer.
- The `groundLayerMask` is used to filter clicks that hit the ground to set a target for the commander.
- The `currentCommander` stores the currently selected commander unit.

Each frame, the `Update` method checks for mouse button inputs:

- If the left mouse button (`0`) is clicked, a raycast checks two things. First, if it hits a commander object, that object becomes the current unit to move. Second, if the raycast hits the ground and there's a selected commander, the script then sets the target position for that commander using the click's hit point. This would move the unit using its `NavMeshAgent`.
- If the right mouse button (`1`) is clicked, a raycast checks if a commander is hit. If no commander is hit, the script clears the `currentCommander`, and you can no longer set a target.

How to use this script:
1. Attach this script to an empty GameObject in your scene.
2. Set up your commander units with Collider components and a NavMeshAgent to allow them to navigate the scene using Unity's NavMesh system.
3. Place your commanders on a unique layer (e.g., "Commander") and set the `commanderLayerMask` in the RTSController inspector to this layer.
4. Set the `groundLayerMask` to the layer that represents the ground or navigable areas in your scene.
5. Run your game and test the selection and commanding of units.

Keep in mind that you might need to tweak this script to fit your exact game setup, such as how your ground and unit layers are defined, or how you set up the NavMeshAgents for pathfinding.
